222→export const uploadJournalContentService = async(
223→    content,
224→    title,
225→    userId,
226→    remixSourceJournalId = null,
227→    isRemix = false,
228→    promptId = null
229→) =>{
230→    if(!userId){
231→        console.error('userId is undefined');
232→        throw {status: 400, error: 'userId is undefined'};
233→    }
234→
235→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
236→
237→    if(!trimmedTitle){
238→        console.error('title is missing!');
239→        throw {status: 400, error: 'title is missing!'};
240→    }
241→
242→    const shouldSaveRemixMetadata = Boolean(
243→        remixSourceJournalId
244→        && typeof remixSourceJournalId === 'string'
245→        && remixSourceJournalId.trim()
246→    );
247→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
248→
249→    if(!content){
250→        console.error('content is missing for text post!');
251→        throw {status: 400, error: 'content is missing for text post'};
252→    }
253→
254→    const parseData = parseTextContentSafely(content);
255→    if(!parseData){
256→        console.error('error while parsing text content data');
257→        throw {status: 400, error: 'error while parsing text content data'};
258→    }
259→
260→    const embeddingBody = parseData.wholeText || '';
261→    const payload = {
262→        user_id: userId,
263→        title: trimmedTitle,
264→        post_type: POST_TYPE_TEXT,
265→        content: content,
266→    };
267→
268→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
269→
270→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
271→        console.error('error while generating embeddings on a post!');
272→        throw {status: 400, error: 'error while generating embeddings on a post!'};
273→    }
274→
275→    const insertPayload = {
276→        ...payload,
277→        embeddings: embeddingResult
278→    };
279→
280→    if(normalizedIsRemix){
281→        insertPayload.is_remix = true;
282→    }
283→    if(shouldSaveRemixMetadata){
284→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
285→    }
286→    if(promptId){
287→        const parsedPromptId = parseInt(promptId, 10);
288→        if(!isNaN(parsedPromptId)){
289→            insertPayload.prompt_id = parsedPromptId;
290→        }
291→    }
292→
293→    let {error} = await supabase
294→    .from('journals')
295→    .insert(insertPayload);
296→
297→    if(error){
298→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
299→        if(missingRemixColumns){
300→            const fallbackPayload = {
301→                ...payload,
302→                embeddings: embeddingResult
303→            };
304→
305→            const retry = await supabase
306→            .from('journals')
307→            .insert(fallbackPayload);
308→            error = retry.error;
309→        }
310→    }
311→
312→    if(error){
313→        console.error('supabase error while uploading content:',error.message);
314→        throw {status: 500, error: 'supabase error while uploading content'};
315→    }
316→
317→    // Non-fatal: record publish for writing streak
318→    let streakResult = null;
319→    try {
320→        const { recordPublishForStreak } = await import('./streakService.js');
321→        streakResult = await recordPublishForStreak(userId);
322→    } catch (streakErr) {
323→        console.error('non-fatal: streak record failed:', streakErr?.message || streakErr);
324→    }
325→
326→    return { success: true, streakResult };
327→}
