import { uploadUserDataService, updateUserDataService, uploadBackgroundService, uploadJournalImageService, uploadJournalContentService, updateJournalService, addReplyOpinionService, updateRepostCaptionService, completeOnboardingService } from "../services/uploadService.js";

export const uploadUserDataController = async(req, res) =>{
    const {bio, name, username} = req.body;
    const file = req.file;
    const userId = req.userId;
    const userEmail = req.authUser?.email;

    try {
        await uploadUserDataService(bio, name, file, userId, userEmail, username)
        return res.status(200).json({message: 'success'})
    } catch (error) {
        console.error(error);
        const status = error?.status || 500;
        return res.status(status).json({error: error?.error || 'error upload user data'})
    }
}

export const updateUserDataController = async(req, res) =>{
    const {
        name,
        bio,
        profileBg,
        dominantColors,
        secondaryColors,
        fontColor,
        profile_font_color: profileFontColorFromBody,
        fontColors
    } = await req.body;
    const image = req.file;
    const userId = req.userId;
    const profileFontColor = profileFontColorFromBody || fontColor || fontColors;

    try {
        const data =  await updateUserDataService(
            name,
            bio,
            profileBg,
            dominantColors,
            secondaryColors,
            profileFontColor,
            userId,
            image
        );
        return res.status(200).json({data: data});
    } catch (error) {
        console.error('error updating user data', error);
        return res.status(500).json({error: 'error updating user data'});
    }
}


