.settings-page {
    max-width: 520px;
    margin: 0 auto;
    padding: 32px 20px 64px;
    display: flex;
    flex-direction: column;
    gap: 32px;
}

.settings-header {
    display: flex;
    align-items: center;
    gap: 12px;
}

.settings-back-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 8px;
    border: 1px solid var(--border-card);
    background: var(--bg-card);
    color: var(--text-secondary);
    cursor: pointer;
    transition: border-color 0.2s ease, color 0.2s ease;
}

.settings-back-btn:hover {
    border-color: var(--accent-amber);
    color: var(--accent-amber);
}

.settings-title {
    font-family: "Playfair Display", serif;
    font-size: 1.4rem;
    font-weight: 600;
    letter-spacing: -0.02em;
    color: var(--text-heading);
    margin: 0;
}

.settings-section {
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    padding: 28px 24px;
    display: flex;
    flex-direction: column;
    gap: 16px;
    box-shadow: var(--shadow-card-sm);
}

.settings-section-title {
    font-family: var(--font-ui);
    font-size: 0.95rem;
    font-weight: 600;
    color: var(--text-heading);
    margin: 0;
    padding-bottom: 12px;
    border-bottom: 1px solid var(--border-card);
}

.settings-current-value {
    font-family: var(--font-ui);
    font-size: 0.85rem;
    color: var(--text-muted);
    margin: 0;
}

.settings-current-value strong {
    color: var(--text-secondary);
    font-weight: 500;
}

.settings-form {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.settings-field {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.settings-field label {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 600;
    color: var(--text-muted);
    letter-spacing: 0.12em;
    text-transform: uppercase;
}

/* ── Input styles (scoped to settings page) ── */
.settings-page .auth-input {
    font-family: var(--font-ui);
    width: 100%;
    border: 1px solid var(--border-card);
    background: var(--bg-primary);
    padding: 14px 16px;
    border-radius: 8px;
    font-size: 0.95rem;
    color: var(--text-primary);
    box-sizing: border-box;
    transition: border-color 0.2s ease, box-shadow 0.2s ease, background-color 0.2s ease;
}

.settings-page .auth-input::placeholder {
    color: var(--text-faint);
    font-style: italic;
}

.settings-page .auth-input:hover {
    border-color: var(--border-light);
}

.settings-page .auth-input:focus {
    outline: none;
    border-color: var(--accent-amber);
    box-shadow: 0 0 0 3px rgba(212, 168, 83, 0.12);
    background: var(--bg-primary);
}

.settings-page .input-with-action {
    position: relative;
    display: flex;
    align-items: center;
}

.settings-page .input-with-action .auth-input {
    padding-right: 72px;
}

.settings-page .show-toggle {
    position: absolute;
    right: 12px;
    background: var(--bg-pill);
    border: none;
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 600;
    letter-spacing: 0.04em;
    text-transform: uppercase;
    color: var(--text-muted);
    cursor: pointer;
    padding: 6px 10px;
    border-radius: 4px;
    transition: background-color 0.15s ease, color 0.15s ease;
}

.settings-page .show-toggle:hover {
    background: var(--bg-hover);
    color: var(--accent-amber);
}

/* ── Buttons ── */
.settings-page .primary-button {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    width: 100%;
    padding: 14px 20px;
    border-radius: 8px;
    border: none;
    background: var(--text-heading);
    color: var(--bg-primary);
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    cursor: pointer;
    transition: transform 0.15s ease, box-shadow 0.2s ease, background-color 0.2s ease;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

.settings-page .primary-button:hover:not(:disabled) {
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
}

.settings-page .primary-button:active:not(:disabled) {
    transform: translateY(0);
}

.settings-page .primary-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    box-shadow: none;
}

.settings-page .button-label {
    display: inline-block;
}

.settings-page .button-spinner {
    width: 14px;
    height: 14px;
    border-radius: 50%;
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-top-color: #fff;
    animation: settings-spin 0.7s linear infinite;
}

@keyframes settings-spin {
    to { transform: rotate(360deg); }
}

/* ── Messages ── */
.settings-page .form-message {
    padding: 12px 14px;
    border-radius: 8px;
    font-family: var(--font-ui);
    font-size: 0.85rem;
    font-weight: 500;
    border: 1px solid transparent;
    animation: settings-fadeIn 0.3s ease;
}

@keyframes settings-fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

.settings-page .form-message.error {
    background: var(--color-danger-bg);
    color: var(--color-danger);
    border-color: rgba(220, 38, 38, 0.2);
}

.settings-page .form-message.success {
    background: var(--color-success-bg);
    color: var(--color-success);
    border-color: rgba(22, 163, 74, 0.2);
}

/* ── Dark mode ── */
[data-theme="dark"] .settings-page .auth-input {
    background: var(--bg-elevated);
    color: var(--text-primary);
    border-color: var(--border-light);
}

[data-theme="dark"] .settings-page .auth-input::placeholder {
    color: var(--text-muted);
}

[data-theme="dark"] .settings-page .auth-input:focus {
    background: var(--bg-elevated);
}

[data-theme="dark"] .settings-page .primary-button {
    background: var(--accent-amber);
    color: #1A1612;
}

[data-theme="dark"] .settings-page .primary-button:hover:not(:disabled) {
    box-shadow: 0 4px 20px rgba(212, 168, 83, 0.25);
}

@media (max-width: 600px) {
    .settings-page {
        padding: 20px 16px 48px;
    }

    .settings-section {
        padding: 20px 16px;
    }

    .settings-title {
        font-size: 1.2rem;
    }
}

