        .from('follows')
        .select('*', {count: 'exact', head: true})
        .eq('follower_id', userId)

        const isFollowingPromise = supabase
        .from('follows')
        .select('*', {count: 'exact', head: true})
        .eq('follower_id', loggedInUserId)
        .eq('following_id', userId)

