                    </button>
                </form>

                {emailError && (
                    <div className="form-message error" role="alert">{emailError}</div>
                )}
                {emailSuccess && (
                    <div className="form-message success" role="status">{emailSuccess}</div>
                )}
            </section>
        </div>
    );
};

export default SettingsPage;

