.settings-page .primary-button:hover:not(:disabled) {
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
}

.settings-page .primary-button:active:not(:disabled) {
    transform: translateY(0);
}

.settings-page .primary-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    box-shadow: none;
}

.settings-page .button-label {
    display: inline-block;
}

.settings-page .button-spinner {
    width: 14px;
    height: 14px;
    border-radius: 50%;
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-top-color: #fff;
    animation: settings-spin 0.7s linear infinite;
}

@keyframes settings-spin {
    to { transform: rotate(360deg); }
}

/* ── Messages ── */
.settings-page .form-message {
    padding: 12px 14px;
    border-radius: 8px;
    font-family: var(--font-ui);
    font-size: 0.85rem;
    font-weight: 500;
    border: 1px solid transparent;
    animation: settings-fadeIn 0.3s ease;
}

@keyframes settings-fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

.settings-page .form-message.error {
    background: var(--color-danger-bg);
    color: var(--color-danger);
    border-color: rgba(220, 38, 38, 0.2);
}

.settings-page .form-message.success {
    background: var(--color-success-bg);
    color: var(--color-success);
    border-color: rgba(22, 163, 74, 0.2);
}

