[data-theme="dark"] .settings-page .auth-input {
    background: var(--bg-elevated);
    color: var(--text-primary);
    border-color: var(--border-light);
}

[data-theme="dark"] .settings-page .auth-input::placeholder {
    color: var(--text-muted);
}

[data-theme="dark"] .settings-page .auth-input:focus {
    background: var(--bg-elevated);
}

[data-theme="dark"] .settings-page .primary-button {
    background: var(--accent-amber);
    color: #1A1612;
}

[data-theme="dark"] .settings-page .primary-button:hover:not(:disabled) {
    box-shadow: 0 4px 20px rgba(212, 168, 83, 0.25);
}

