  1→import supabase from "./supabase.js";
  2→import GenerateEmbeddings from "../utils/GenerateEmbeddings.js";
  3→
  4→// Canonical topics from onboarding wizard (InterestsStep.jsx)
  5→const CANONICAL_TOPICS = [
  6→    'Poetry', 'Fiction', 'Journals', 'Essays',
  7→    'Philosophy', 'Self-Reflection', 'Creative Nonfiction', 'Short Stories',
  8→    'Science', 'Nature', 'Music', 'Art',
  9→    'Travel', 'Technology', 'Mental Health', 'Spirituality',
 10→];
 11→
 12→// In-memory cache: topic string → embedding array
 13→const topicEmbeddingCache = new Map();
 14→
 15→/**
 16→ * Generate a single embedding from an array of interest strings.
 17→ * Joins them into a comma-separated string and runs through the embedding pipeline.
 18→ */
 19→export const generateInterestsEmbedding = async (interests) => {
 20→    if (!Array.isArray(interests) || interests.length === 0) {
 21→        return null;
 22→    }
 23→
 24→    const joined = interests
 25→        .filter(i => typeof i === 'string' && i.trim())
 26→        .join(', ');
 27→
 28→    if (!joined) return null;
 29→
 30→    return GenerateEmbeddings(joined, '');
 31→};
 32→
 33→/**
 34→ * Generate an interests embedding for a user and store it on the users table.
 35→ */
 36→export const updateUserInterestsEmbedding = async (userId, interests) => {
 37→    const embedding = await generateInterestsEmbedding(interests);
 38→    if (!embedding) return;
 39→
 40→    const { error } = await supabase
 41→        .from('users')
 42→        .update({ interests_embedding: embedding })
 43→        .eq('id', userId);
