608→        throw { status: 400, error: 'limit should be integer, not below 1 and higher than 20' };
609→    }
610→
611→    const parsedLimit = parseInt(limit);
612→    const parsedOffset = parseInt(offset) || 0;
613→
614→    const { data: rpcData, error } = await supabase.rpc('get_for_you_feed', {
615→        p_user_id: userId,
616→        p_limit: parsedLimit + 1,
617→        p_offset: parsedOffset
618→    });
