640→        repost_source_journal_id: row.repost_source_journal_id,
641→        repost_caption: row.repost_caption,
642→        prompt_id: row.prompt_id,
643→        users: { id: row.user_obj_id, name: row.user_name, image_url: row.user_image_url, badge: row.user_badge },
644→        like_count: [{ count: Number(row.like_count) }],
645→        reaction_count: [{ count: Number(row.reaction_count) }],
646→        comment_count: [{ count: Number(row.comment_count) }],
647→        bookmark_count: [{ count: Number(row.bookmark_count) }]
648→    }));
649→
650→    // Personalization (same pattern as getFollowingFeedService)
651→    const journalIds = data.map(j => j.id);
652→    const [userLikes, userBookmarks, userReactions] = await Promise.all([
653→        supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
654→        supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
655→        supabase.from('reactions').select('journal_id, reaction_type').in('journal_id', journalIds).eq('user_id', userId)
656→    ]);
657→
658→    const userHasLikedSet = new Set(userLikes.data?.map(j => j.journal_id) || []);
659→    const userHasBookmarkedSet = new Set(userBookmarks.data?.map(j => j.journal_id) || []);
660→    const userReactionMap = new Map((userReactions.data || []).map(r => [r.journal_id, r.reaction_type]));
661→
662→    await attachRepostSources(data);
663→
664→    const formattedData = data.map(journal => ({
665→        ...journal,
666→        has_liked: userHasLikedSet.has(journal.id),
667→        has_bookmarked: userHasBookmarkedSet.has(journal.id),
668→        user_reaction: userReactionMap.get(journal.id) || null
669→    }));
670→
671→    const hasMore = data.length > parsedLimit;
672→    const slicedData = hasMore ? formattedData.slice(0, parsedLimit) : formattedData;
673→
674→    return { data: slicedData, hasMore };
675→}
